# Helper to format bytes in human-readable form
def format_bytes(bytes_value: int) -> str:
    value = float(bytes_value)
    for unit in ["B", "KiB", "MiB", "GiB", "TiB"]:
        if value < 1024:
            return f"{value:.1f}{unit}"
        value /= 1024
    return f"{value:.1f}PiB"

